exercises.solution_code:
#include <iostream>
#include <string>

class Greeter
{
public:
    void greet(const std::string& name)
    {
        std::cout << "Hello, " << name << "!\n";
    }
};

class FriendlyGreeter : public Greeter
{
public:
    void greet(const std::string& name)
    {
        Greeter::greet(name);
        std::cout << "Welcome aboard, " << name << "!\n";
    }
};

int main()
{
    std::string name{};
    std::cin >> name;

    FriendlyGreeter fg{};
    fg.greet(name);

    return 0;
}

